import './HeroimgStyls.css';

import React from 'react'
import jj from "../assets/1.jpn.jpg"
const heroImg = () => {
  return (
    <div className='hero'>
        <div className='mask'>
            <img className="into-img"
            src={jj}/>
        </div>
    </div>
  )
}

export default heroImg
